**Parameters:**
```json
{
  "properties": {
    "command": {
      "description": "Command to run (default: make check)",
      "type": "string"
    },
    "packages": {
      "description": "Specific packages to test (e.g. ['./roadmap/...'])",
      "items": {
        "type": "string"
      },
      "type": "array"
    }
  },
  "required": [],
  "type": "object"
}
```

